import React, { useState } from 'react';
import './App.css';

function App() {
    const [tokenId, setTokenId] = useState('');
    const [selectedAsset, setSelectedAsset] = useState('');

    const handleTokenChange = (event) => {
        setTokenId(event.target.value);
    };

    const handleAssetChange = (event) => {
        setSelectedAsset(event.target.value);
    };

    const handleSubmit = () => {
        console.log('Token ID Submitted:', tokenId);
        console.log('Selected Asset:', selectedAsset);
        // Add logic to send tokenId and selectedAsset to Flask backend
    };

    return (
        <div className="App">
            <header className="App-header">
                <input type="text" placeholder="Enter Token ID" value={tokenId} onChange={handleTokenChange} />
                <select value={selectedAsset} onChange={handleAssetChange}>
                    <option value="">Select an Asset</option>
                    <option value="gm">gm</option>
                    <option value="cheers">cheers</option>
                    <option value="peace">peace</option>
                    <option value="head">head</option>
                    <option value="christmas">christmas</option>
                </select>
                <button onClick={handleSubmit}>Submit</button>
                {/* Placeholder for asset display */}
                <div id="asset-display">
                    <p>Selected assets will be displayed here</p>
                </div>
            </header>
        </div>
    );
}

export default App;
